use anyhow::{Context, Result};
use std::fs;
use std::path::Path;

fn read_file(path: &Path) -> Result<String> {
    fs::read_to_string(path)
        .with_context(|| format!("Failed to read {}", path.display()))
}

fn read_lines(path: &Path) -> Result<Vec<String>> {
    let content = read_file(path)?;
    Ok(content.lines().map(String::from).collect())
}

use std::fs::File;
use std::io::{BufRead, BufReader};
use anyhow::Result;

fn count_matching_lines(path: &str, pattern: &str) -> Result<usize> {
    let file = File::open(path)?;
    let reader = BufReader::new(file);
    let mut count = 0;

    for line in reader.lines() {
        let line = line?;
        if line.contains(pattern) {
            count += 1;
        }
    }

    Ok(count)
}

use std::fs::File;
use std::io::{BufWriter, Write};
use anyhow::Result;

fn write_report(path: &str, data: &[(String, u32)]) -> Result<()> {
    let file = File::create(path)?;
    let mut writer = BufWriter::new(file);

    writeln!(writer, "Name,Count")?;
    for (name, count) in data {
        writeln!(writer, "{},{}", name, count)?;
    }

    writer.flush()?;
    Ok(())
}

use std::io::{self, BufRead, Read, Write};

fn read_input(path: Option<&str>) -> Result<String, io::Error> {
    match path {
        Some("-") | None => {
            let mut buf = String::new();
            io::stdin().read_to_string(&mut buf)?;
            Ok(buf)
        }
        Some(path) => std::fs::read_to_string(path),
    }
}

fn write_output(path: Option<&str>, content: &str) -> Result<(), io::Error> {
    match path {
        Some("-") | None => {
            io::stdout().write_all(content.as_bytes())?;
            Ok(())
        }
        Some(path) => std::fs::write(path, content),
    }
}
